  const [loading, setLoading] = useState(true);

  const fetchStats = useCallback(async () => {
    setLoading(true);
    const data = await DatabaseService.getSystemStats();
    setStats(data);
    setLoading(false);
  }, []);

  useEffect(() => { fetchStats(); }, [fetchStats]);

  return (
    <div className="space-y-12 animate-in fade-in">
      <div className="flex justify-between items-end">
          <div>
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">Sistem <span className="text-blue-500">Özeti</span></h2>
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] mt-2 italic">Global platform anlık metrikleri</p>
          </div>
          <button onClick={fetchStats} className="p-3 bg-white/5 rounded-xl text-slate-500 hover:text-white transition-all">
            <RefreshCw size={18} className={loading ? 'animate-spin' : ''} />
          </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Toplam Kullanıcı', value: stats.totalUsers, icon: Users, color: 'text-blue-500' },
          { label: 'Aktif Botlar', value: stats.activeBots, icon: Bot, color: 'text-emerald-500' },
          { label: 'Toplam Kanal', value: stats.totalChannels, icon: Radio, color: 'text-purple-500' },
          { label: 'Yayındaki Reklam', value: stats.activePromos, icon: Megaphone, color: 'text-orange-500' },
        ].map((stat, i) => (
          <div key={i} className="bg-slate-900/40 border border-white/5 p-8 rounded-[40px] flex items-center gap-6 shadow-xl backdrop-blur-sm transition-all hover:scale-[1.02]">
            <div className={`p-4 bg-slate-950 rounded-2xl ${stat.color} border border-white/5 shadow-inner`}><stat.icon size={24} /></div>
            <div>
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-1">{stat.label}</p>
              <p className="text-2xl font-black text-white italic tracking-tighter leading-none">{loading ? '...' : stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 bg-slate-900/40 border border-white/5 rounded-[44px] p-10 h-80 flex items-center justify-center">
              <div className="text-center opacity-20">
                  <BarChart3 size={64} className="mx-auto mb-4 text-slate-600" />
                  <p className="text-xs font-black uppercase tracking-widest">İstatistik Grafiği V4 Motoruyla Gelecek</p>
              </div>
          </div>
          <div className="bg-slate-900/40 border border-white/5 rounded-[44px] p-10 h-80 flex flex-col">
              <h4 className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-6 border-b border-white/5 pb-4 italic">Sistem Durumu</h4>
              <div className="flex-1 space-y-6 overflow-y-auto no-scrollbar">
                  {[
                    { label: 'Veritabanı', status: 'Online', color: 'text-emerald-500' },
                    { label: 'Telegram API', status: 'Bağlı', color: 'text-emerald-500' },
                    { label: 'Reklam Motoru', status: 'Aktif', color: 'text-blue-500' },
                    { label: 'Ödeme Sistemi', status: 'Beklemede', color: 'text-orange-500' },
                  ].map((sys, i) => (
                      <div key={i} className="flex justify-between items-center">
                          <p className="text-[10px] font-black text-slate-300 uppercase italic">{sys.label}</p>
                          <p className={`text-[8px] font-black uppercase tracking-widest ${sys.color}`}>{sys.status}</p>
