};

/**
 * UserManagement: Kullanıcı Listesi (Canlı)
 */
const UserManagement = () => {
    const [users, setUsers] = useState<User[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    const fetchUsers = useCallback(async () => {
        setIsLoading(true);
        try {
            const data = await DatabaseService.getUsers();
            setUsers(data);
        } catch (e) { console.error(e); }
        setIsLoading(false);
    }, []);

    useEffect(() => { fetchUsers(); }, [fetchUsers]);

    const toggleStatus = async (user: User) => {
      const newStatus = user.status === 'Active' ? 'Passive' : 'Active';
      if(confirm(`${user.name} kullanıcısını ${newStatus === 'Active' ? 'Aktif' : 'Pasif'} yapmak istiyor musunuz?`)) {
        await DatabaseService.updateUserStatus(user.id, newStatus);
        fetchUsers();
      }
    };

    return (
        <div className="space-y-8 animate-in fade-in">
            <div className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">Kullanıcı <span className="text-blue-500">Yönetimi</span></h2>
              <button onClick={fetchUsers} className="p-3 bg-white/5 rounded-xl text-slate-500 hover:text-white"><RefreshCw size={18} className={isLoading ? 'animate-spin' : ''}/></button>
            </div>
            {isLoading ? (
                <div className="flex justify-center py-24"><Loader2 className="animate-spin text-blue-500" size={32} /></div>
            ) : (
                <div className="bg-slate-900/40 border border-white/5 rounded-[44px] overflow-hidden shadow-2xl">
                    <table className="w-full text-left">
                        <thead className="bg-white/5 border-b border-white/5">
                            <tr className="text-[9px] font-black text-slate-600 uppercase tracking-widest">
                                <th className="px-8 py-6">Kullanıcı Profil</th>
                                <th className="px-8 py-6">Durum</th>
                                <th className="px-8 py-6">Katılım Tarihi</th>
                                <th className="px-8 py-6 text-right">Eylemler</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {users.map(u => (
                                <tr key={u.id} className="group hover:bg-white/5 transition-colors">
                                    <td className="px-8 py-6">
                                        <div className="flex items-center gap-4">
                                            <img src={u.avatar} className="w-10 h-10 rounded-xl bg-slate-950 object-cover border border-white/5" />
                                            <div>
                                                <p className="text-xs font-black text-white italic uppercase tracking-tight">{u.name}</p>
                                                <p className="text-[10px] text-slate-500">@{u.username}</p>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-8 py-6">
                                        <button 
                                          onClick={() => toggleStatus(u)}
                                          className={`px-3 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-widest border transition-all ${u.status === 'Active' ? 'text-emerald-500 bg-emerald-500/10 border-emerald-500/20' : 'text-red-500 bg-red-500/10 border-red-500/20'}`}
                                        >
                                            {u.status}
                                        </button>
                                    </td>
                                    <td className="px-8 py-6 text-[10px] text-slate-400 font-bold uppercase italic">{new Date(u.joinDate).toLocaleDateString('tr-TR')}</td>
                                    <td className="px-8 py-6 text-right">
                                        <button 
                                          onClick={() => {
                                            const msg = prompt(`${u.name} kullanıcısına bildirim gönder:`);
                                            if(msg) DatabaseService.sendUserNotification(u.id, "Admin Mesajı", msg, 'system');
                                          }}
                                          className="p-3 bg-white/5 rounded-xl text-slate-500 hover:text-blue-500 transition-all border border-transparent hover:border-blue-500/20"
                                        >
                                          <Bell size={16}/>
                                        </button>
                                    </td>
                                </tr>
                            ))}
                            {users.length === 0 && (
                              <tr><td colSpan={4} className="py-20 text-center text-slate-600 font-black uppercase tracking-widest text-xs italic">Kayıtlı kullanıcı bulunamadı.</td></tr>
                            )}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
}

/**
 * BotManagement: Mağaza Bot Yönetimi (Tam Dinamik)
 */
const BotManagement = () => {
    const [bots, setBots] = useState<BotType[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingBot, setEditingBot] = useState<Partial<BotType> | null>(null);

