        setIsLoading(true);
        try {
          const data = await DatabaseService.getBots();
          setBots(data);
        } catch (e) { console.error(e); }
        setIsLoading(false);
    };

    useEffect(() => { load(); }, []);

    const handleSave = async (e: React.FormEvent) => {
