      if(!editingBot?.name) return;
      setIsLoading(true);
      try {
        await DatabaseService.saveBot(editingBot);
        setIsModalOpen(false);
        load();
      } catch (e) { alert("Bot kaydedilemedi."); }
      setIsLoading(false);
    };

    return (
        <div className="space-y-12 animate-in fade-in">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                  <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Bot <span className="text-emerald-500">Kataloğu</span></h2>
                  <p className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] mt-2 italic">Mağazada listelenen tüm ürünler</p>
