                                    <p className="text-xl font-black text-white italic tracking-tighter">₺{bot.price}</p>
                                </div>
                            </div>
                            <div>
                                <h4 className="text-lg font-black text-white uppercase italic tracking-tighter mb-2">{bot.name}</h4>
                                <p className="text-[10px] text-slate-500 line-clamp-2 uppercase italic font-bold leading-relaxed opacity-60">{bot.description}</p>
                            </div>
                            <div className="flex gap-3 mt-auto">
