                    ))}
                    {bots.length === 0 && (
                      <div className="col-span-full py-24 text-center border-2 border-dashed border-white/5 rounded-[44px]">
                          <Bot size={48} className="mx-auto mb-4 text-slate-800" />
                          <p className="text-slate-600 font-black uppercase tracking-widest text-xs italic">Katalog henüz boş.</p>
                      </div>
                    )}
                </div>
            )}

            {isModalOpen && editingBot && (
              <div className="fixed inset-0 z-[150] bg-black/95 flex items-center justify-center p-6 backdrop-blur-3xl animate-in fade-in">
                <div className="bg-[#020617] border border-white/10 rounded-[44px] w-full max-w-2xl overflow-hidden shadow-2xl relative">
                   <div className="p-10 border-b border-white/5 flex justify-between items-center">
                      <h3 className="text-xl font-black text-white italic uppercase tracking-tighter">Bot <span className="text-blue-500">Editörü</span></h3>
                      <button onClick={() => setIsModalOpen(false)} className="p-3 bg-white/5 rounded-2xl text-slate-500 hover:text-white transition-all"><X size={20}/></button>
                   </div>
                   <form onSubmit={handleSave} className="p-10 space-y-8 max-h-[70vh] overflow-y-auto no-scrollbar">
                      <AdminInput label="BOT ADI" value={editingBot.name} onChange={(v:any)=>setEditingBot({...editingBot, name:v})} placeholder="Örn: Moderasyon Pro" />
                      <AdminInput label="AÇIKLAMA" value={editingBot.description} onChange={(v:any)=>setEditingBot({...editingBot, description:v})} rows={3} placeholder="Botun işlevini kısaca anlatın..." />
                      <div className="grid grid-cols-2 gap-8">
                        <AdminInput label="FİYAT (TL)" type="number" value={editingBot.price} onChange={(v:any)=>setEditingBot({...editingBot, price: Number(v)})} />
                        <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-4 italic">KATEGORİ</label>
                          <select 
                            value={editingBot.category} 
                            onChange={e => setEditingBot({...editingBot, category: e.target.value})}
                            className="w-full h-18 bg-slate-950 border border-white/5 px-8 rounded-[28px] text-[11px] font-black outline-none text-slate-200 uppercase italic tracking-widest"
                          >
                            <option value="productivity">Üretkenlik</option>
                            <option value="games">Oyun</option>
                            <option value="utilities">Araçlar</option>
