 */

const { Telegraf, Markup, session } = require('telegraf');
const { createClient } = require('@supabase/supabase-js');

// --- YAPILANDIRMA ---
// NOT: Gerçek ortamda bunları process.env üzerinden almalısınız.
const BOT_TOKEN = 'YOUR_BOT_TOKEN_BURAYA'; 
const MINI_APP_URL = 'https://botlyhub-v3.vercel.app'; // Sizin Mini App linkiniz
const SUPABASE_URL = 'https://ybnxfwqrduuinzgnbymc.supabase.co';
const SUPABASE_KEY = 'YOUR_SUPABASE_SERVICE_ROLE_KEY'; // Kayıt yetkisi için Service Role Key kullanın

