/**
 * REKLAM DAĞITIM MOTORU (Queue Processor)
 * Her 30 saniyede bir veritabanını kontrol eder.
 */
async function processQueue() {
    console.log('[Engine]: Reklam kuyruğu kontrol ediliyor...');
    try {
        // 1. Durumu 'sending' (yayınlanıyor) olan reklamları çek
        const { data: queue, error: qErr } = await supabase
            .from('promotions')
            .select('*')
            .eq('status', 'sending');

        if (qErr || !queue || queue.length === 0) return;

        // 2. Yayın izni açık olan kanalları çek (revenue_enabled: true)
        const { data: targets, error: tErr } = await supabase
            .from('channels')
            .select('*')
            .eq('revenue_enabled', true);

        if (tErr || !targets || targets.length === 0) {
            console.log('[Engine]: Yayın yapılacak aktif kanal bulunamadı.');
            return;
        }

        for (const promo of queue) {
            console.log(`[Engine]: '${promo.title}' reklamı işleniyor...`);

            // Daha önce bu reklamın gönderildiği kanalları takip et (Hata almamak için kontrol ekliyoruz)
            const history = new Set(promo.processed_channels || []);
            let successCount = promo.channel_count || 0;
            let totalReach = promo.total_reach || 0;

            for (const target of targets) {
                // Eğer bu kanala zaten gönderildiyse atla
                if (history.has(target.telegram_id)) continue;

                try {
                    const keyboard = promo.button_text && promo.button_link 
                        ? Markup.inlineKeyboard([[Markup.button.url(promo.button_text, promo.button_link)]]) 
                        : null;

