 */
async function processBroadcastQueue() {
    try {
        // 1. Bekleyen reklamları çek
        const { data: queue, error: qErr } = await supabase
            .from('promotions')
            .select('*')
            .eq('status', 'sending');

        if (qErr) throw qErr;

        if (!queue || queue.length === 0) {
            console.log('[Broadcast]: Dağıtılacak reklam bulunamadı.');
            return;
        }

        // 2. Aktif kanalları çek
        const { data: channels, error: cErr } = await supabase
            .from('channels')
            .select('*')
            .eq('revenue_enabled', true);

        if (cErr) throw cErr;

        if (!channels || channels.length === 0) {
            console.log('[Broadcast]: Yayın izni olan aktif kanal bulunamadı.');
            return;
        }

        console.log(`[Broadcast]: ${queue.length} reklam, ${channels.length} kanala dağıtılıyor...`);

        for (const promo of queue) {
            // Gönderim geçmişini String olarak karşılaştır (BigInt hatalarını önler)
            const processedList = (promo.processed_channels || []).map(id => String(id));
            const history = new Set(processedList);

            let successCount = promo.channel_count || 0;
            let totalReach = promo.total_reach || 0;
            let newlyProcessed = false;

            for (const channel of channels) {
                const channelIdStr = String(channel.telegram_id);

                if (history.has(channelIdStr)) continue;

                try {
                    const keyboard = promo.button_text && promo.button_link 
                        ? Markup.inlineKeyboard([[Markup.button.url(promo.button_text, promo.button_link)]]) 
                        : null;

                    const message = `<b>${promo.title}</b>\n\n${promo.content}`;

                    let sentResult;
                    if (promo.image_url && promo.image_url.startsWith('http')) {
                        sentResult = await bot.telegram.sendPhoto(channel.telegram_id, promo.image_url, {
                            caption: message,
                            parse_mode: 'HTML',
                            ...keyboard
                        });
                    } else {
                        sentResult = await bot.telegram.sendMessage(channel.telegram_id, message, {
                            parse_mode: 'HTML',
                            ...keyboard
                        });
                    }

                    if (sentResult) {
                        successCount++;
                        totalReach += (channel.member_count || 0);
                        history.add(channelIdStr);
                        newlyProcessed = true;
                        console.log(`[DAĞITIM]: OK -> ${channel.name}`);
                    }

                    // Telegram Flood limitleri için kısa bekleme
                    await new Promise(r => setTimeout(r, 600)); 

                } catch (e) {
                    const errorMsg = e.message.toLowerCase();
                    console.error(`[DAĞITIM]: FAIL -> ${channel.name}: ${e.message}`);

                    if (errorMsg.includes('kicked') || errorMsg.includes('blocked') || errorMsg.includes('chat not found')) {
                        await supabase.from('channels').update({ revenue_enabled: false }).eq('id', channel.id);
                    }
                }
            }

            // Veritabanını güncelle
            if (newlyProcessed) {
                const status = history.size >= channels.length ? 'sent' : 'sending';
                await supabase.from('promotions').update({ 
                    channel_count: successCount, 
                    total_reach: totalReach,
                    processed_channels: Array.from(history),
                    status: status,
                    sent_at: status === 'sent' ? new Date().toISOString() : null
                }).eq('id', promo.id);
            }
        }
    } catch (err) {
        console.error('[Broadcast Motoru Hatası]:', err);
    }
}

