                    if (promo.image_url && promo.image_url.startsWith('http')) {
                        sentResult = await bot.telegram.sendPhoto(channel.telegram_id, promo.image_url, {
                            caption: message,
                            parse_mode: 'HTML',
                            ...keyboard
                        });
                    } else {
                        sentResult = await bot.telegram.sendMessage(channel.telegram_id, message, {
                            parse_mode: 'HTML',
                            ...keyboard
                        });
                    }

                    if (sentResult) {
                        history.add(channelIdStr);
                        successCountInThisRun++;
                        console.log(`[BAŞARILI]: ${channel.name} kanalına iletildi.`);
                    }

                    await new Promise(r => setTimeout(r, 1000)); // Flood protection

                } catch (e) {
                    console.error(`[HATA]: ${channel.name} gönderimi başarısız: ${e.message}`);
                    if (e.message.includes('blocked') || e.message.includes('kicked')) {
                        await supabase.from('channels').update({ revenue_enabled: false }).eq('id', channel.id);
                    }
                }
            }

            // Durum Güncellemesi
            const isFinished = history.size >= channels.length;
            await supabase.from('promotions').update({ 
                channel_count: history.size,
                processed_channels: Array.from(history),
                status: isFinished ? 'sent' : 'sending',
                sent_at: isFinished ? new Date().toISOString() : null
            }).eq('id', promo.id);
        }
    } catch (err) {
        console.error('[CRITICAL ENGINE ERROR]:', err);
    }
    console.log('--- Broadcast Cycle Tamamlandı ---');
}

