  static async savePromotion(promo: Partial<Promotion>) {
    const payload = {
        id: promo.id || Math.floor(Math.random() * 999999).toString(),
        title: promo.title,
        content: promo.content,
        image_url: promo.image_url,
        button_text: promo.button_text,
