        title: '',
        message: '',
        type: 'system',
        target_type: 'global',
        user_id: ''
    });

    const load = useCallback(async () => {
        setIsLoading(true);
        const data = await DatabaseService.getNotifications();
        setNotes(data);
        setIsLoading(false);
