    const [promos, setPromos] = useState<Promotion[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingPromo, setEditingPromo] = useState<any>(null);
    const [updatingId, setUpdatingId] = useState<string | null>(null);

    const load = useCallback(async () => {
        setIsLoading(true);
        try {
            const data = await DatabaseService.getPromotions();
            setPromos(data);
        } catch (e) {
            console.error("Promos Load Error:", e);
        } finally {
            setIsLoading(false);
        }
    }, []);

    useEffect(() => { load(); }, [load]);

    /**
     * FIXED TOGGLE LOGIC:
     * Durumu anlık olarak 'sending'e çeker.
     */
    const handleToggleStatus = async (p: Promotion) => {
        if (updatingId) return; 

        const nextStatus: Promotion['status'] = p.status === 'sending' ? 'pending' : 'sending';
        setUpdatingId(p.id);

        // UI optimistik güncelleme
        const prev = [...promos];
        setPromos(current => current.map(item => item.id === p.id ? { ...item, status: nextStatus } : item));

        try {
            await DatabaseService.updatePromotionStatus(p.id, nextStatus);
            // Veriyi Supabase'den tazeleyelim
            const fresh = await DatabaseService.getPromotions();
            setPromos(fresh);
        } catch (error: any) {
            console.error("Promotion Toggle Error:", error);
            setPromos(prev); // Rollback
            alert(error.message || "İşlem sırasında bir hata oluştu.");
        } finally {
            setUpdatingId(null);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            // ID alanı boş ise DatabaseService.savePromotion bunu yeni kayıt olarak algılayacak
            await DatabaseService.savePromotion({ 
                ...editingPromo, 
                id: editingPromo.id === '' ? undefined : editingPromo.id
            }); 
            setIsModalOpen(false); 
            load(); 
        } catch (err: any) {
            console.error("Save Promotion Error:", err);
            // Sunucudan gelen hatayı doğrudan gösteriyoruz ki sorun net anlaşılsın
            alert(`Sistem Hatası: ${err.message || 'Kayıt yapılamadı.'}`);
        }
    };

    const getStatusBadge = (status: string) => {
        switch(status) {
            case 'sending': return <span className="px-3 py-1 bg-blue-500/10 text-blue-500 border border-blue-500/20 rounded-full text-[9px] font-black uppercase animate-pulse">AKTİF YAYINDA</span>;
            case 'sent': return <span className="px-3 py-1 bg-emerald-500/10 text-emerald-500 border border-emerald-500/20 rounded-full text-[9px] font-black uppercase">TAMAMLANDI</span>;
            case 'failed': return <span className="px-3 py-1 bg-red-500/10 text-red-500 border border-red-500/20 rounded-full text-[9px] font-black uppercase">HATA</span>;
            default: return <span className="px-3 py-1 bg-slate-500/10 text-slate-500 border border-white/5 rounded-full text-[9px] font-black uppercase">BEKLEMEDE</span>;
        }
    };

    return (
        <div className="space-y-12 animate-in fade-in">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                    <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">Promo <span className="text-blue-500">Engine</span></h2>
                    <p className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] mt-2 italic">Kanallar üzerinden toplu reklam dağıtımı yapın</p>
                </div>
                <button 
                    onClick={() => { 
                        setEditingPromo({ id: '', title: '', content: '', image_url: '', status: 'pending', button_text: 'İNCELE', button_link: '', click_count: 0, processed_channels: [] }); 
                        setIsModalOpen(true); 
                    }} 
                    className="w-full md:w-auto bg-emerald-600 hover:bg-emerald-500 px-10 py-5 rounded-[28px] text-[11px] font-black uppercase tracking-widest shadow-2xl active:scale-95 border-b-4 border-emerald-900 transition-all flex items-center gap-3"
                >
                    <Plus size={18} /> YENİ REKLAM OLUŞTUR
                </button>
            </div>

            {isLoading && updatingId === null ? (
                <div className="flex flex-col items-center justify-center py-24 gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={32} />
                    <span className="text-[10px] font-black text-slate-800 uppercase tracking-widest italic">Senkronize Ediliyor...</span>
                </div>
            ) : promos.length === 0 ? (
                <div className="bg-slate-900/20 border-2 border-dashed border-slate-800 rounded-[48px] p-24 text-center">
                    <Megaphone size={48} className="text-slate-800 mx-auto mb-6" />
                    <p className="text-slate-600 font-black uppercase italic tracking-widest">Henüz bir kampanya tanımlanmadı.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 gap-6">
                    {promos.map(p => (
                        <div key={p.id} className="bg-slate-900/40 border border-white/5 rounded-[48px] p-10 flex flex-col lg:flex-row items-center justify-between group shadow-2xl hover:border-blue-500/20 transition-all">
                            <div className="flex-1 min-w-0 text-center lg:text-left">
                                <div className="flex items-center justify-center lg:justify-start gap-3 mb-4">
                                    {getStatusBadge(p.status)}
                                    <span className="text-[10px] font-bold text-slate-700 uppercase tracking-[0.2em]">{new Date(p.created_at).toLocaleDateString()}</span>
                                </div>
                                <h4 className="text-2xl font-black italic uppercase text-white truncate mb-4">{p.title}</h4>
                                <div className="flex items-center justify-center lg:justify-start gap-8">
                                    <div className="flex items-center gap-2">
                                        <Monitor size={14} className="text-slate-500" />
                                        <span className="text-[10px] font-black text-slate-500 uppercase">{p.channel_count || 0} KANAL</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <TrendingUp size={14} className="text-blue-500" />
                                        <span className="text-[10px] font-black text-blue-500 uppercase">{p.total_reach?.toLocaleString() || 0} ERİŞİM</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <MousePointer2 size={14} className="text-emerald-500" />
                                        <span className="text-[10px] font-black text-emerald-500 uppercase">{p.click_count || 0} TIKLAMA</span>
                                    </div>
                                </div>
                            </div>
                            <div className="flex gap-3 mt-8 lg:mt-0">
                                <button 
                                    disabled={updatingId === p.id}
                                    onClick={() => handleToggleStatus(p)} 
                                    className={`px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95 flex items-center gap-2 min-w-[160px] justify-center ${
                                        updatingId === p.id 
                                        ? 'bg-slate-800 text-slate-600 opacity-50' 
                                        : p.status === 'sending' 
                                          ? 'bg-orange-500/10 text-orange-500 border border-orange-500/20 shadow-lg' 
                                          : 'bg-blue-600 text-white shadow-xl shadow-blue-900/40 hover:bg-blue-500'
                                    }`}
                                >
                                    {updatingId === p.id ? (
                                        <Loader2 className="animate-spin" size={14} />
                                    ) : (
                                        <>
                                            {p.status === 'sending' ? 'YAYINI DURDUR' : 'YAYINA AL'}
                                            <Send size={14} />
                                        </>
                                    )}
                                </button>
                                <button 
                                    onClick={() => { setEditingPromo(p); setIsModalOpen(true); }}
                                    className="p-4 bg-white/5 rounded-2xl text-blue-400 hover:bg-blue-600 hover:text-white transition-all shadow-xl"
                                >
                                    <Edit3 size={20}/>
                                </button>
                                <button 
                                    onClick={async () => { if(confirm('Bu kampanya silinsin mi?')) { await DatabaseService.deletePromotion(p.id); load(); } }} 
                                    className="p-4 bg-white/5 rounded-2xl text-red-500 hover:bg-red-500 hover:text-white transition-all shadow-xl"
                                >
                                    <Trash2 size={20}/>
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {isModalOpen && editingPromo && (
                <div className="fixed inset-0 z-[110] bg-black/98 flex items-center justify-center p-0 lg:p-6 backdrop-blur-3xl animate-in fade-in">
                    <div className="bg-[#020617] p-8 lg:p-14 rounded-t-[40px] lg:rounded-[64px] w-full max-w-7xl h-[94vh] lg:h-[90vh] overflow-hidden border-t lg:border border-white/10 shadow-2xl relative flex flex-col lg:flex-row gap-12">
                        <button onClick={() => setIsModalOpen(false)} className="absolute top-8 right-8 p-4 bg-white/5 rounded-2xl text-slate-500 hover:text-white z-50 transition-all">
                            <X size={24}/>
                        </button>

                        {/* LEFT: Ad Composer Form */}
                        <div className="flex-1 overflow-y-auto pr-2 no-scrollbar space-y-8">
                            <div>
                                <h3 className="text-3xl font-black mb-2 uppercase italic tracking-tighter">Campaign <span className="text-emerald-500">Forge</span></h3>
                                <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest italic">Yayınlanacak reklamın içeriğini tasarlayın</p>
                            </div>

                            <form onSubmit={handleSave} className="space-y-8 pb-10">
                                <AdminInput label="REKLAM BAŞLIĞI" value={editingPromo.title} onChange={(v:any)=>setEditingPromo({...editingPromo, title:v})} placeholder="Örn: Haftalık Kampanya" />

                                <div className="space-y-2">
                                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-4 italic">ANA MESAJ (HTML DESTEKLİ)</label>
                                    <textarea 
                                        value={editingPromo.content} 
                                        onChange={e => setEditingPromo({...editingPromo, content: e.target.value})} 
                                        className="w-full bg-slate-950 border border-white/5 p-8 rounded-[36px] text-[11px] font-black h-40 outline-none text-slate-400 focus:border-emerald-500/30 uppercase italic leading-relaxed" 
                                        placeholder="Kanalda görünecek reklam metni..." 
                                    />
                                </div>

                                <AdminInput label="GÖRSEL URL (OPSİYONEL)" value={editingPromo.image_url} onChange={(v:any)=>setEditingPromo({...editingPromo, image_url:v})} icon={ImageIcon} placeholder="https://..." />

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <AdminInput label="BUTON METNİ" value={editingPromo.button_text} onChange={(v:any)=>setEditingPromo({...editingPromo, button_text:v})} placeholder="İNCELE" />
                                    <AdminInput label="BUTON LİNKİ" value={editingPromo.button_link} onChange={(v:any)=>setEditingPromo({...editingPromo, button_link:v})} icon={Link2} placeholder="https://t.me/..." />
                                </div>

                                <button type="submit" className="w-full h-20 bg-blue-600 hover:bg-blue-500 rounded-[32px] font-black text-[12px] uppercase tracking-[0.4em] shadow-2xl border-b-8 border-blue-900 transition-all active:translate-y-1 active:border-b-4">KAMPANYAYI SİSTEME KAYDET</button>
                            </form>
                        </div>

                        {/* RIGHT: LIVE HOLOGRAPHIC TELEGRAM SIMULATOR */}
                        <div className="hidden lg:flex w-[460px] flex-col items-center justify-center bg-slate-900/20 border-l border-white/5 p-12 relative overflow-hidden">
                            <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-emerald-600/5 via-transparent to-transparent"></div>

                            <div className="text-center mb-12 space-y-2">
                                <span className="text-[10px] font-black text-blue-500 uppercase tracking-[0.5em] italic block">TELEGRAM PREVIEW</span>
                                <p className="text-[9px] font-black text-slate-700 uppercase tracking-widest">REAL-TIME SIMULATOR</p>
                            </div>

                            {/* Telegram Message UI */}
                            <div className="w-full bg-[#020617] border border-white/10 rounded-[40px] overflow-hidden shadow-[0_50px_100px_rgba(0,0,0,0.6)] animate-in zoom-in-95">
                                {editingPromo.image_url && editingPromo.image_url.startsWith('http') ? (
                                    <img src={editingPromo.image_url} className="w-full h-48 object-cover border-b border-white/5" onError={(e)=>(e.target as any).src=''} />
                                ) : (
                                    <div className="w-full h-32 bg-slate-900/40 flex flex-col items-center justify-center border-b border-white/5">
                                        <ImageIcon className="text-slate-800 mb-2" size={32} />
                                        <span className="text-[8px] font-black text-slate-800 uppercase tracking-widest">Görsel Alanı</span>
                                    </div>
                                )}
                                <div className="p-8 space-y-4">
                                    <h5 className="text-white font-black text-lg italic uppercase tracking-tighter truncate leading-none">{editingPromo.title || 'REKLAM BAŞLIĞI'}</h5>
                                    <p className="text-slate-400 text-[10px] font-bold uppercase italic leading-relaxed line-clamp-4 min-h-[60px] whitespace-pre-wrap">{editingPromo.content || 'Yayın içeriği burada görünecek...'}</p>

                                    {editingPromo.button_text && (
                                        <div className="pt-4">
                                            <div className="w-full py-4 bg-blue-600/10 border border-blue-500/30 rounded-2xl text-blue-500 text-[9px] font-black text-center uppercase tracking-widest">
                                                {editingPromo.button_text}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>

                            <div className="mt-12 flex items-center gap-3 opacity-30">
                                <AlertCircle size={14} className="text-slate-500" />
                                <span className="text-[8px] font-black text-slate-500 uppercase tracking-[0.3em]">Görünüm Telegram istemcisine göre değişebilir</span>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default AdminDashboard;

import { createClient } from '@supabase/supabase-js';
import { Bot, User, Channel, Announcement, Notification, UserBot, ActivityLog, Promotion } from '../types';

const SUPABASE_URL = 'https://ybnxfwqrduuinzgnbymc.supabase.co'; 
const SUPABASE_ANON_KEY = 'sb_publishable_VeYQ304ZpUpj3ymB3ihpjw_jt49W1G-'; 

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

export class DatabaseService {

  // --- PROMOTIONS ---
  static async getPromotions(): Promise<Promotion[]> {
    const { data, error } = await supabase
      .from('promotions')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) {
        console.error("Promotions Fetch Error:", error);
        return [];
    }
    // Veritabanında sütunlar yoksa bile uygulamanın çökmemesi için varsayılan değerler
    return (data || []).map(p => ({
        ...p,
        click_count: Number(p.click_count || 0),
        total_reach: Number(p.total_reach || 0),
        channel_count: Number(p.channel_count || 0),
        processed_channels: p.processed_channels || []
    }));
  }

  static async savePromotion(promo: Partial<Promotion>) {
    // SADECE TABLODA OLDUĞUNDAN EMİN OLDUĞUMUZ KOLONLARI GÖNDERİYORUZ
    // Hata veren 'click_count' ve benzeri sayaçları çıkardık
    const payload: any = {
        title: promo.title,
        content: promo.content,
        image_url: promo.image_url || null,
        button_text: promo.button_text || 'İNCELE',
        button_link: promo.button_link || null,
        status: promo.status || 'pending'
    };

    if (promo.id && promo.id !== '') {
        // GÜNCELLEME (UPDATE)
        console.log(`Güncelleniyor (UUID): ${promo.id}`);
        const { error } = await supabase
            .from('promotions')
            .update(payload)
            .eq('id', promo.id);

        if (error) {
            console.error("Supabase Update Hatası:", error);
            throw new Error(`Güncelleme başarısız: ${error.message}`);
        }
    } else {
        // YENİ KAYIT (INSERT)
        console.log("Yeni kayıt ekleniyor...");
        payload.created_at = new Date().toISOString();

        // click_count ve total_reach veritabanında "default 0" olarak tanımlı olmalıdır
        // Eğer tabloda yoklarsa, onları göndermek hata almamıza sebep olur.
        const { error } = await supabase
            .from('promotions')
            .insert([payload]);

        if (error) {
            console.error("Supabase Insert Hatası:", error);
            throw new Error(`Ekleme başarısız: ${error.message}`);
        }
    }
  }

  static async deletePromotion(id: string) {
    const { error } = await supabase.from('promotions').delete().eq('id', id);
    if (error) throw error;
  }

  static async updatePromotionStatus(id: string, status: Promotion['status']) {
      console.log(`Durum güncelleniyor: ${id} -> ${status}`);

      const { error } = await supabase
        .from('promotions')
        .update({ status: status })
        .eq('id', id);

      if (error) {
          console.error("Statü Güncelleme Hatası:", error);
          throw new Error(`Statü değişikliği başarısız: ${error.message}`);
      }

      return true;
  }

  // --- USERS ---
  static async getUsers(): Promise<User[]> {
    const { data, error } = await supabase.from('users').select('*').order('joindate', { ascending: false });
    if (error) return [];
    return (data || []).map(u => ({ 
        id: u.id, 
        name: u.name, 
        username: u.username, 
        avatar: u.avatar, 
        role: (u.role || 'User') as any, 
        status: (u.status || 'Active') as any, 
        badges: u.badges || [], 
        joinDate: u.joindate, 
        email: u.email,
        canPublishPromos: u.can_publish_promos 
    }));
  }

  static async getUserById(userId: string): Promise<User | null> {
    const { data, error } = await supabase.from('users').select('*').eq('id', userId.toString()).maybeSingle();
    if (error || !data) return null;
    return { 
        id: data.id, 
        name: data.name, 
        username: data.username, 
        avatar: data.avatar, 
        role: (data.role || 'User') as any, 
        status: (data.status || 'Active') as any, 
        badges: data.badges || [], 
        joinDate: data.joindate, 
        email: data.email,
        canPublishPromos: data.can_publish_promos 
    };
  }

  static async updateUserStatus(userId: string, status: 'Active' | 'Passive') {
    const { error } = await supabase.from('users').update({ status }).eq('id', userId.toString());
    if (error) throw error;
  }

  // --- NOTIFICATIONS (ADMIN CONTROL) ---
  static async sendGlobalNotification(title: string, message: string, type: Notification['type'] = 'system') {
      const { error } = await supabase.from('notifications').insert([{ 
          id: Math.floor(Math.random() * 999999999).toString(), 
          title, 
          message, 
          type, 
          date: new Date().toISOString(), 
          isRead: false, 
          target_type: 'global',
          view_count: 0
      }]);
      if (error) throw error;
  }

  static async sendUserNotification(userId: string, title: string, message: string, type: Notification['type'] = 'system') {
      const { error } = await supabase.from('notifications').insert([{ 
          id: Math.floor(Math.random() * 999999999).toString(), 
          user_id: userId.toString(),
          title, 
          message, 
          type, 
          date: new Date().toISOString(), 
          isRead: false, 
          target_type: 'user',
          view_count: 0
      }]);
      if (error) throw error;
  }

  static async deleteNotification(id: string) {
      const { error } = await supabase.from('notifications').delete().eq('id', id);
      if (error) throw error;
  }

  static async incrementNotificationView(id: string) {
      const { data } = await supabase.from('notifications').select('view_count').eq('id', id).maybeSingle();
      if (data) {
          const current = Number(data.view_count || 0);
          await supabase.from('notifications').update({ view_count: current + 1 }).eq('id', id);
      }
  }

  // --- LOGS ---
  static async getActivityLogs(): Promise<ActivityLog[]> {
    const { data, error } = await supabase.from('activity_logs').select('*').order('created_at', { ascending: false }).limit(50);
    if (error) return [];
    return data || [];
  }

  // --- BOT MANAGEMENT ---
  static async getBotsWithStats(): Promise<any[]> {
    const { data: bots } = await supabase.from('bots').select('*').order('id', { ascending: false });
    const { data: userBots } = await supabase.from('user_bots').select('bot_id');
    return (bots || []).map(bot => ({ 
        ...bot, 
        ownerCount: (userBots || []).filter((ub: any) => ub.bot_id === bot.id).length 
    }));
  }

  static async saveBot(bot: any) {
    const { error } = await supabase.from('bots').upsert({ 
        id: bot.id, 
        name: bot.name, 
        description: bot.description, 
        price: Number(bot.price), 
        category: bot.category, 
        bot_link: bot.bot_link, 
        screenshots: bot.screenshots || [], 
        icon: bot.icon, 
        is_premium: Boolean(bot.is_premium) 
    });
    if (error) throw error;
  }

  static async deleteBot(id: string) {
    const { error } = await supabase.from('bots').delete().eq('id', id);
    if (error) throw error;
  }

  // --- FINANCE ---
  static async getAllPurchases() {
    const { data } = await supabase.from('user_bots').select('*, users(*), bots(*)').order('acquired_at', { ascending: false });
    return data || [];
  }

  // --- STATS ---
  static async getAdminStats() {
    const [u, b, l, s, c] = await Promise.all([
        supabase.from('users').select('*', { count: 'exact', head: true }),
        supabase.from('bots').select('*', { count: 'exact', head: true }),
        supabase.from('activity_logs').select('*', { count: 'exact', head: true }),
        supabase.from('user_bots').select('*', { count: 'exact', head: true }),
        supabase.from('channels').select('revenue', { head: false })
    ]);
    const totalRevenue = (c.data || []).reduce((acc, curr) => acc + (curr.revenue || 0), 0);
    return { userCount: u.count || 0, botCount: b.count || 0, logCount: l.count || 0, salesCount: s.count || 0, totalRevenue };
  }

  // --- ANNOUNCEMENTS ---
  static async saveAnnouncement(ann: any) {
    const { error } = await supabase.from('announcements').upsert({ 
        id: ann.id || Math.floor(Math.random() * 999999).toString(), 
        title: ann.title, 
        description: ann.description, 
        button_text: ann.button_text, 
        button_link: ann.button_link, 
        icon_name: ann.icon_name, 
        color_scheme: ann.color_scheme, 
        is_active: Boolean(ann.is_active), 
        action_type: ann.action_type, 
        content_detail: ann.content_detail || '' 
    });
    if (error) throw error;
  }

  static async deleteAnnouncement(id: string) {
    const { error } = await supabase.from('announcements').delete().eq('id', id);
    if (error) throw error;
  }

  // --- BOT DATA ---
  static async getUserBots(userId: string): Promise<UserBot[]> {
    const { data } = await supabase.from('user_bots').select('*, bots(*)').eq('user_id', userId.toString());
    return (data || []).map((item: any) => ({ ...item.bots, expiryDate: item.expiryDate, ownership_id: item.id, is_premium: item.is_premium, isActive: item.is_active, revenueEnabled: false })).filter(b => b.id);
  }

  static async getBots(): Promise<Bot[]> {
    const { data } = await supabase.from('bots').select('*').order('id', { ascending: false });
    return data || [];
  }

  static async getBotById(id: string): Promise<Bot | null> {
    const { data } = await supabase.from('bots').select('*').eq('id', id).maybeSingle();
